import React, { useEffect, useState } from 'react';
import './portaladm.css';

// Importar todos os módulos separados
import Dashboard from './modules/dashboard/Dashboard';
import Clientes from './modules/clientes/Clientes';
import Servicos from './modules/servicos/Servicos';
import Agenda from './modules/agenda/Agenda';
import CadastroColaboradores from './modules/colaboradores/cadastro_colaboradores/CadastroColaboradores';
import RHDP from './modules/rhdp/RHDP';
import SSMA_SST from './modules/colaboradores/ssma_sst1/SSMA_SST';
import Escalas from './modules/colaboradores/escalas_e_folgas/Escalas';
import Equipes from './modules/equipes/Equipes';
import Veiculos from './modules/veiculos/Veiculos';
import Documentos from './modules/documentos/Documentos';
import Relatorios from './modules/relatorios/Relatorios';
import Configuracoes from './modules/configuracoes/Configuracoes';

const PortalAdm = () => {
  const [activeModule, setActiveModule] = useState(() => {
    return localStorage.getItem('portaladm.activeModule') || 'dashboard';
  });
  const [colaboradoresOpen, setColaboradoresOpen] = useState(() => {
    return localStorage.getItem('portaladm.menu.colaboradoresOpen') === '1';
  });

  const menuItems = [
    { id: 'dashboard', label: 'Dashboard Geral', icon: '' },
    { id: 'clientes', label: 'Clientes', icon: '' },
    { id: 'servicos', label: 'Serviços', icon: '' },
    { id: 'agenda', label: 'Agenda Operacional', icon: '' },
    { id: 'colaboradores', label: 'Colaboradores', icon: '', kind: 'parent' },
    { id: 'rhdp', label: 'RH/DP', icon: '' },
    { id: 'equipes', label: 'Equipes', icon: '' },
    { id: 'veiculos', label: 'Veículos', icon: '' },
    { id: 'documentos', label: 'Documentos', icon: '' },
    { id: 'relatorios', label: 'Relatórios', icon: '' },
    { id: 'configuracoes', label: 'Configurações', icon: '' }
  ];

  useEffect(() => {
    localStorage.setItem('portaladm.activeModule', activeModule);
  }, [activeModule]);

  useEffect(() => {
    localStorage.setItem('portaladm.menu.colaboradoresOpen', colaboradoresOpen ? '1' : '0');
  }, [colaboradoresOpen]);

  const handleLogout = () => {
    localStorage.removeItem('userEmail');
    localStorage.removeItem('userType');
    localStorage.removeItem('userToken');
    window.location.href = '/login';
  };

  const renderContent = () => {
    switch(activeModule) {
      case 'dashboard':
        return <Dashboard />;
      case 'clientes':
        return <Clientes />;
      case 'servicos':
        return <Servicos />;
      case 'agenda':
        return <Agenda />;
      case 'colaboradores/cadastro':
        return <CadastroColaboradores />;
      case 'rhdp':
        return <RHDP />;
      case 'colaboradores/ssma-sst':
        return <SSMA_SST />;
      case 'colaboradores/escala-folga':
        return <Escalas />;
      case 'equipes':
        return <Equipes />;
      case 'veiculos':
        return <Veiculos />;
      case 'documentos':
        return <Documentos />;
      case 'relatorios':
        return <Relatorios />;
      case 'configuracoes':
        return <Configuracoes />;
      default:
        return (
          <div className="portaladm-default">
            <h2>{menuItems.find(item => item.id === activeModule)?.label}</h2>
            <p>Módulo em desenvolvimento...</p>
          </div>
        );
    }
  };

  const isColaboradoresActive = activeModule.startsWith('colaboradores/');

  const handleToggleColaboradores = () => {
    const next = !colaboradoresOpen;
    setColaboradoresOpen(next);
    if (next && !isColaboradoresActive) setActiveModule('colaboradores/cadastro');
  };

  return (
    <div className="portaladm-container">
      {/* Header Corporativo */}
      <header className="portaladm-header">
        <div className="portaladm-logo">
          <img 
            src="img/logo1.png" 
            alt="TOPLAB" 
            className="portaladm-logo-img"
          />
          <div>
            <h1>Sistema TOP LIMP</h1>
            <div className="system-subtitle">Gestão Operacional Integrada</div>
          </div>
        </div>
        <div className="portaladm-user">
          <span>Administrador</span>
          <button className="portaladm-logout" onClick={handleLogout}>
            Sair
          </button>
        </div>
      </header>

      {/* Layout Principal */}
      <div className="portaladm-layout">
        {/* Menu Lateral Corporativo */}
        <aside className="portaladm-sidebar">
          <div className="menu-content">
            {menuItems.map((item) => {
              if (item.kind === 'parent' && item.id === 'colaboradores') {
                return (
                  <div key={item.id}>
                    <button
                      className={`menu-item menu-parent ${isColaboradoresActive ? 'active' : ''}`}
                      onClick={handleToggleColaboradores}
                      aria-expanded={colaboradoresOpen}
                    >
                      <span className="menu-icon">{item.icon}</span>
                      <span className="menu-label">{item.label}</span>
                      <span className="menu-chevron">{colaboradoresOpen ? '▾' : '▸'}</span>
                    </button>

                    {colaboradoresOpen && (
                      <div className="menu-submenu">
                        <button
                          className={`menu-subitem ${activeModule === 'colaboradores/cadastro' ? 'active' : ''}`}
                          onClick={() => setActiveModule('colaboradores/cadastro')}
                        >
                          Cadastro de colaboradores
                        </button>
                        <button
                          className={`menu-subitem ${activeModule === 'colaboradores/ssma-sst' ? 'active' : ''}`}
                          onClick={() => setActiveModule('colaboradores/ssma-sst')}
                        >
                          SSMA/SST
                        </button>
                        <button
                          className={`menu-subitem ${activeModule === 'colaboradores/escala-folga' ? 'active' : ''}`}
                          onClick={() => setActiveModule('colaboradores/escala-folga')}
                        >
                          Escala de folga
                        </button>
                      </div>
                    )}
                  </div>
                );
              }

              return (
                <button
                  key={item.id}
                  className={`menu-item ${activeModule === item.id ? 'active' : ''}`}
                  onClick={() => setActiveModule(item.id)}
                >
                  <span className="menu-icon">{item.icon}</span>
                  <span className="menu-label">{item.label}</span>
                </button>
              );
            })}
          </div>
        </aside>

        {/* Conteúdo Principal */}
        <main className="portaladm-main">
          <div className="portaladm-content">
            {renderContent()}
          </div>
        </main>
      </div>
    </div>
  );
};

export default PortalAdm;
